import React, { useEffect, useState } from 'react';
import { getStats } from '../services/api';
import { Link } from 'react-router-dom';

const StatCard = ({ label, value, icon, color }) => (
  <div className="card" style={{ padding: '20px 24px', display: 'flex', alignItems: 'center', gap: 16 }}>
    <div style={{ width: 48, height: 48, borderRadius: 12, background: color + '20', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22 }}>{icon}</div>
    <div>
      <div style={{ fontSize: 26, fontWeight: 700, color: '#1a202c' }}>{value ?? '—'}</div>
      <div style={{ fontSize: 12, color: '#64748b', marginTop: 2 }}>{label}</div>
    </div>
  </div>
);

export default function Dashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getStats().then(r => setStats(r.data.data)).catch(() => {}).finally(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ padding: 32, color: '#64748b' }}>Loading...</div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Dashboard</div>
          <div className="page-subtitle">Overview of patient records</div>
        </div>
        <Link to="/patients/new" className="btn btn-primary">+ New Patient</Link>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16, marginBottom: 28 }}>
        <StatCard label="Total Patients" value={stats?.total_patients} icon="👥" color="#2b7de9" />
        <StatCard label="Total Visits" value={stats?.total_visits} icon="🩺" color="#27ae60" />
        <StatCard label="Visits Today" value={stats?.visits_today} icon="📅" color="#f39c12" />
        <StatCard label="This Month" value={stats?.this_month} icon="📈" color="#9b59b6" />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        <div className="card">
          <div style={{ padding: '16px 20px', borderBottom: '1px solid #e2e8f0', fontWeight: 600, fontSize: 14 }}>Recent Visits</div>
          <div>
            {stats?.recent_visits?.length === 0 && <div className="empty-state">No visits yet</div>}
            {stats?.recent_visits?.map((v, i) => (
              <div key={i} style={{ padding: '12px 20px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13 }}>{v.patient_name}</div>
                  <div style={{ fontSize: 12, color: '#64748b' }}>{v.reason} · {v.village}</div>
                </div>
                <div style={{ fontSize: 11, color: '#94a3b8', whiteSpace: 'nowrap', marginLeft: 8 }}>{new Date(v.visit_date).toLocaleDateString('en-IN')}</div>
              </div>
            ))}
          </div>
        </div>

        <div className="card">
          <div style={{ padding: '16px 20px', borderBottom: '1px solid #e2e8f0', fontWeight: 600, fontSize: 14 }}>Patient Distribution</div>
          <div style={{ padding: '20px' }}>
            {stats?.gender_dist?.map(g => (
              <div key={g.gender} style={{ marginBottom: 14 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 5 }}>
                  <span>{g.gender}</span>
                  <span style={{ fontWeight: 600 }}>{g.count}</span>
                </div>
                <div style={{ height: 8, background: '#f1f5f9', borderRadius: 4, overflow: 'hidden' }}>
                  <div style={{ height: '100%', width: `${(g.count / stats.total_patients) * 100}%`, background: g.gender === 'Female' ? '#ec4899' : g.gender === 'Male' ? '#2b7de9' : '#f59e0b', borderRadius: 4 }} />
                </div>
              </div>
            ))}
            <div style={{ marginTop: 20 }}>
              <Link to="/patients" className="btn btn-outline" style={{ width: '100%', justifyContent: 'center' }}>View All Patients →</Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
